mapper.select:
SELECT br.id, br.book_id, br.reader_id, br.borrow_date, br.due_date, br.return_date, br.status, br.fine, br.remark, b.name AS book_name, r.name AS reader_name FROM borrow br LEFT JOIN book b ON br.book_id = b.id LEFT JOIN reader r ON br.reader_id = r.id
AND br.status = #{status}
AND br.reader_id = #{readerId}
ORDER BY br.id DESC

mapper.update:
UPDATE borrow
SET return_date = #{returnDate}, status = #{status}, fine = #{fine}
WHERE id = #{id}
